// Validation function
const requiredFields = ['name', 'email', 'projectType', 'description'];
const errors = [];

const data = $input.item.json.body;

// Check required fields
for (const field of requiredFields) {
  if (!data[field] || String(data[field]).trim() === '') {
    errors.push(`Missing required field: ${field}`);
  }
}

// Validate email format
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (data.email && !emailRegex.test(data.email)) {
  errors.push('Invalid email format');
}

// Validate project type
const validProjectTypes = ['ai-integration', 'virtual-reality', '3d-production', 'tech-solutions', 'consulting'];
if (data.projectType && !validProjectTypes.includes(data.projectType)) {
  errors.push('Invalid project type');
}

// Validate description length
if (data.description && (data.description.length < 10 || data.description.length > 500)) {
  errors.push('Description must be between 10 and 500 characters');
}

// Return result
return {
  valid: errors.length === 0,
  errors: errors,
  data: data
};

// Format message for Telegram
const data = $input.item.json.data;

const projectTypeNames = {
  'ai-integration': 'AI Integration',
  'virtual-reality': 'Virtual Reality',
  '3d-production': '3D Production',
  'tech-solutions': 'Technical Solutions',
  'consulting': 'Consulting'
};

const message = `🔔 *NEW CONSULTATION REQUEST*

👤 *Name:* ${data.name}
📧 *Email:* ${data.email}

🎯 *Project Type:* ${projectTypeNames[data.projectType] || data.projectType}

📝 *Description:*
${data.description}

🕐 *Submitted:* ${new Date().toLocaleString()}
🌐 *Source:* Website`;

return {
  ...data,
  telegramMessage: message
};
